I found way to control SocketIO handler with web api.

Draft code:

```
import socketio
import eventlet.wsgi
from flask import Flask, jsonify, abort, make_response, request


app = Flask(__name__)
sio = socketio.Server()
handler_rule = {}

@app.route('/')
def index():
    return 'Hello folks! This is mock SocketIO server for testing.'

@app.route('/set_sio_handler', methods=['POST'])
def set_sio_handler():
    handler_rule['command'] = request.json['command']
    handler_rule['result'] = request.json['result']
    return 'Success!!', 200

@sio.on('commands')
def message_handler(sid, msg):
    if msg['data']['command'] == handler_rule['command']:
        response_msg = {'handler': msg['handler'],
                        'data': {'result': handler_rule['result'],
                                 'request_id': msg['data']['request_id']}}
        sio.emit('commands', response_msg)

if __name__ == '__main__':
    mid = socketio.Middleware(sio, app)
    eventlet.wsgi.server(eventlet.listen(('127.0.0.1', 1234)), mid)
```

